use cardano/transaction.{Transaction, OutputReference}

pub type TraceDatum {
  owner: ByteArray,
  amount: Int,
}

validator trace_validator {
  spend(datum: Option<TraceDatum>, _redeemer: Data, _ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let msg =
          string.concat(
            string.concat(
              string.concat(@"owner_amount:", string.from_bytearray(d.owner)),
              @"_",
            ),
            string.from_int(d.amount),
          )
        trace msg
        let signatories = self.extra_signatories
        list.has(signatories, d.owner)
      }
    }
  }
}

use aiken/primitive/string
use cardano/transaction.{Transaction, OutputReference}

pub type RegistryDatum {
  id: Int,
  owner: ByteArray,
}

fn owner_signed(tx: Transaction, owner: ByteArray) -> Bool {
  let signatories = tx.extra_signatories
  list.any(signatories, fn(sig) { sig == owner })
}

validator labeled_registry(label_prefix: ByteArray) {
  spend(
    datum: Option<RegistryDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let label =
          string.concat(
            string.from_bytearray(label_prefix),
            string.from_int(d.id),
          )
        let _label_tag = string.to_bytearray(label)
        owner_signed(self, d.owner)
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type NameDatum {
  name_bytes: ByteArray,
  min_len: Int,
}

validator name_length_check {
  spend(
    datum: Option<NameDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let name_str = string.from_bytearray(d.name_bytes)
        let name_ba = string.to_bytearray(name_str)
        let actual_len = builtin.length_of_bytearray(name_ba)
        actual_len >= d.min_len
      }
    }
  }
}
